INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('japandi', 'Japandi', '和洋折衷', 'Japanese x Scandinavian "warm minimalism;" Light, airy, uncluttered living, while still feeling “Japanese.”   It’s also practical for holiday homes (easy to clean, durable, doesn’t date quickly).', 'active', 1, 'Japanese x Scandinavian "warm minimalism;" Light, airy, uncluttered living, while still feeling “Japanese.”   It’s also practical for holiday homes (easy to clean, durable, doesn’t date quickly).', 'Pale timber, neutral textiles, low-slung furniture, simple lines, matte black accents, paper/linen lighting, minimal decor.', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('modern-japanese-minimal', 'Modern Japanese minimal', 'モダンミニマル', 'MUJI-like, functional, storage-first; “Hotel-clean” vibe, high function for smaller footprints, and it pairs well with Japan-specific features (genkan, built-ins, compact wet areas)', 'active', 2, 'MUJI-like, functional, storage-first; “Hotel-clean” vibe, high function for smaller footprints, and it pairs well with Japan-specific features (genkan, built-ins, compact wet areas)', 'Built-in storage, hidden utilities, simple wood + white palette, clean joinery, uncluttered surfaces, quality lighting.', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('contemporary-ski-chalet-luxury', 'Contemporary ski-chalet luxury', 'コンテンポラリースキーリゾートラグジュアリー', 'It matches what many Aussies already rent in Japan—designer chalets with a warm lodge feel and “holiday wow factor.”', 'active', 3, 'It matches what many Aussies already rent in Japan—designer chalets with a warm lodge feel and “holiday wow factor.”', 'Darker timbers, big communal living-dining, feature fireplace, plush seating, mood lighting, statement dining table, spa-style baths/onsen feel.', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('traditional-japanese-wa', 'Traditional Japanese (Wa)', '和風', 'The bath experience is a uniquely Japanese luxury that translates directly into guest reviews and repeat stays—especially for ski/onsen towns. Classic Japanese architecture with tatami, shoji, engawa', 'active', 4, 'The bath experience is a uniquely Japanese luxury that translates directly into guest reviews and repeat stays—especially for ski/onsen towns. Classic Japanese architecture with tatami, shoji, engawa', 'Natural wood, paper screens, low furniture, garden views.  Calm stone/wood textures, indirect lighting, deep soaking tub, spa shower, towel/linen storage, dehumidifying ventilation.', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('modern-rustic-japanese', 'Modern-rustic Japanese', 'モダン古民家', 'Minka-lite: traditional warmth, not museum offers “authentic Japan” but also comfort and usability.', 'active', 5, 'Minka-lite: traditional warmth, not museum offers “authentic Japan” but also comfort and usability.', 'preserved beams/columns, timber textures, selected tatami room (1 is common), modern kitchen/bath, upgraded insulation/heating, curated traditional accents (norens, ceramics) rather than heavy themeing.', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('alpine-mountain-house', 'Alpine Mountain House', 'モダン山小屋風', 'Emphasizes coziness, character, and texture', 'active', 6, 'Emphasizes coziness, character, and texture', 'Timber, open-plan kitchen, layered textures; One timber feature element (slat wall or ceiling beam stain), not whole-house timber cladding', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('anime-nostalgia', 'Anime Nostalgia', 'アニメな日常昭和レトロ', '“Lived-in” coziness not luxury', 'active', 7, '“Lived-in” coziness not luxury', 'Warm timber;  Natural wood tones (stain existing beams/frames rather than re-cladding) + simple joinery, Old-school details (wood frames, ceramic/enameled fixtures, retro lighting)', '');
INSERT INTO design_styles (slug, name_en, name_ja, description, status, sort_order, description_long, key_features, typical_regions) VALUES ('contemporary-hamptons-coastal', 'Contemporary / Hamptons Coastal', 'ビーチハウス', 'Light, airy palettes; natural textures; indoor–outdoor flow. It’s the default “holiday” look across AU media and design inspiration with a view of water.', 'active', 8, 'Light, airy palettes; natural textures; indoor–outdoor flow. It’s the default “holiday” look across AU media and design inspiration with a view of water.', 'Big windows & openings, White/greige walls, light timber, linen, rattan/textural weaves, simple layered lighting, minimal clutter.', '');
