INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('new-replaced-system-kitchen', 'New / replaced system kitchen', 'システムキッチン交換', 'Replace old kitchen with modern integrated “system kitchen” (cabinets, sink, cooktop, ventilation).', 'active', 1, 'wet_areas', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('new-replaced-unit-bath', 'New / replaced unit bath', 'ユニットバス交換', 'Replace bath area with prefabricated sealed unit bath (tub + walls + ceiling), often with drying/ventilation.', 'active', 2, 'wet_areas', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('new-replaced-toilets', 'New / replaced toilet(s)', 'トイレ便器交換', 'Replace toilet bowl/tank and related fittings; may include flooring and ventilation refresh.', 'active', 3, 'wet_areas', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('smart-toilet-heated-bidet-seat', 'Smart Toilet & Heated Bidet Seat', '温水洗浄便座トイレ', 'Install/replace washlet-style toilet seat or integrated smart toilet (heated seat, bidet, deodorizer).', 'active', 4, 'wet_areas', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('second-floor-additional-toilet-refresh', 'Second-floor / additional toilet refresh', '2階トイレ増設・新品交換', 'Add a new toilet or fully replace an upstairs toilet (common in 2-story homes).', 'active', 5, 'wet_areas', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('washstand-vanity-replacement', 'Washstand / vanity replacement', '洗面化粧台交換', 'Replace JP-style vanity unit (sink + mirror cabinet + storage), often in “washroom” zone.', 'active', 6, 'wet_areas', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('wallpaper-cross-replacement', 'Wallpaper / cross replacement', '壁・天井クロス張替え', 'Replace interior vinyl wallpaper (“cross”) on walls/ceilings; patching and underlayer prep as needed.', 'active', 7, 'interior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('flooring-replacement-overlay', 'Flooring replacement / overlay', 'フローリング張替・重ね張り、フロアタイル', 'Replace or overlay floors with new wood flooring, vinyl plank/tile, or refinish where possible.', 'active', 8, 'interior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('lighting-upgrades', 'Lighting upgrades', '照明交換 / LED化', 'Replace fixtures; convert to LED; add brighter/warmer lighting plans for living areas and entrances.', 'active', 9, 'interior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('tatami-sliding-doors-refresh', 'Tatami + sliding doors refresh', '畳・襖/障子などの更新', 'Replace tatami mats (or re-face), and renew fusuma/shoji paper and frames.', 'active', 10, 'interior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('storagecloset-conversion', 'Storage/closet conversion', '押入れ→クローゼット等', 'Convert traditional oshiire (deep closet) into Western-style closet with hang rails/shelves; optimize entry storage.', 'active', 11, 'interior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('exterior-wall-roof-painting', 'Exterior wall + roof painting', '外壁塗装・屋根塗装', 'Repaint exterior cladding and roof; includes sealing, rustproofing, and waterproofing where needed.', 'active', 12, 'exterior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('entrance-door-replacement', 'Entrance door replacement', '玄関扉交換', 'Replace genkan entry door (often with better sealing, insulation, and modern lock set).', 'active', 13, 'exterior', false);
INSERT INTO renovation_features (slug, name_en, name_ja, description, status, sort_order, category, japan_specific) VALUES ('termite-prevention', 'Termite prevention', 'シロアリ防除', 'Chemical treatment and inspection (underfloor/crawlspace), sometimes with warranty period.', 'active', 14, 'interior', false);
